	// Definition of parts
	part def Block__Controller {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
		attribute airTemp : Integer;
		attribute waterTemp : Integer;
		attribute pressure : Integer;
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
		attribute windGust : Integer;
		attribute humidity : Integer;
		attribute wavePropagationDirection : Integer;
		attribute waveEnergySpectrum : Integer;
		attribute waterLevel : Integer;

		// Signals
		in item IMUData :  __type_Controller_IMUData;

		in item GNSSData :  __type_Controller_GNSSData;

		in item AnemometerData :  __type_Controller_AnemometerData;

		in item BarometerData :  __type_Controller_BarometerData;

		in item AirThermometerData :  __type_Controller_AirThermometerData;

		in item WaterThermometerData :  __type_Controller_WaterThermometerData;

		in item HumiditySensorData :  __type_Controller_HumiditySensorData;

		out item toVHF :  __type_Controller_toVHF;


		state mainState__ {
			entry; then start__;


			state readingHumiditySensorData;

			transition from_readingHumiditySensorData__0 first readingHumiditySensorData
			do action  {
				first start;
				then action msg accept HumiditySensorData : __type_Controller_HumiditySensorData;
				then assign humidity := msg.HumiditySensorData.humidity;
				then done;
			}
			then afterReceiving__0;


			state afterReceiving__0;

			transition from_afterReceiving__0__1 first afterReceiving__0
			then computingDerivedMeasurements;


			state readingWaterThermometerData;

			transition from_readingWaterThermometerData__0 first readingWaterThermometerData
			do action  {
				first start;
				then action msg accept WaterThermometerData : __type_Controller_WaterThermometerData;
				then assign waterTemp := msg.WaterThermometerData.waterTemp;
				then done;
			}
			then afterReceiving__1;


			state afterReceiving__1;

			transition from_afterReceiving__1__1 first afterReceiving__1
			then readingHumiditySensorData;


			state readingAirThermometerData;

			transition from_readingAirThermometerData__0 first readingAirThermometerData
			do action  {
				first start;
				then action msg accept AirThermometerData : __type_Controller_AirThermometerData;
				then assign airTemp := msg.AirThermometerData.airTemp;
				then done;
			}
			then afterReceiving__2;


			state afterReceiving__2;

			transition from_afterReceiving__2__1 first afterReceiving__2
			then readingWaterThermometerData;


			state readingBarometerData;

			transition from_readingBarometerData__0 first readingBarometerData
			do action  {
				first start;
				then action msg accept BarometerData : __type_Controller_BarometerData;
				then assign pressure := msg.BarometerData.pressure;
				then done;
			}
			then afterReceiving__3;


			state afterReceiving__3;

			transition from_afterReceiving__3__1 first afterReceiving__3
			then readingAirThermometerData;


			state readingAnemometerData;

			transition from_readingAnemometerData__0 first readingAnemometerData
			do action  {
				first start;
				then action msg accept AnemometerData : __type_Controller_AnemometerData;
				then assign windSpeed := msg.AnemometerData.windSpeed;
				then assign windDirection := msg.AnemometerData.windDirection;
				then done;
			}
			then afterReceiving__4;


			state afterReceiving__4;

			transition from_afterReceiving__4__1 first afterReceiving__4
			then readingBarometerData;


			state readingGNSSData;

			transition from_readingGNSSData__0 first readingGNSSData
			do action  {
				first start;
				then action msg accept GNSSData : __type_Controller_GNSSData;
				then assign GNSS_x := msg.GNSSData.GNSS_x;
				then assign GNSS_y := msg.GNSSData.GNSS_y;
				then assign GNSS_z := msg.GNSSData.GNSS_z;
				then done;
			}
			then afterReceiving__5;


			state afterReceiving__5;

			transition from_afterReceiving__5__1 first afterReceiving__5
			then readingAnemometerData;


			state sendingMeasurements;

			transition from_sendingMeasurements__0 first sendingMeasurements
			do action  {
				first start;
				then assign toVHF.IMU_xAcc := IMU_xAcc;
				then assign toVHF.IMU_yAcc := IMU_yAcc;
				then assign toVHF.IMU_zAcc := IMU_zAcc;
				then assign toVHF.IMU_pitchRate := IMU_pitchRate;
				then assign toVHF.IMU_rollRate := IMU_rollRate;
				then assign toVHF.IMU_yawRate := IMU_yawRate;
				then assign toVHF.GNSS_x := GNSS_x;
				then assign toVHF.GNSS_y := GNSS_y;
				then assign toVHF.GNSS_z := GNSS_z;
				then assign toVHF.airTemp := airTemp;
				then assign toVHF.waterTemp := waterTemp;
				then assign toVHF.pressure := pressure;
				then assign toVHF.windSpeed := windSpeed;
				then assign toVHF.windDirection := windDirection;
				then assign toVHF.windGust := windGust;
				then assign toVHF.humidity := humidity;
				then assign toVHF.wavePropagationDirection := wavePropagationDirection;
				then assign toVHF.waveEnergySpectrum := waveEnergySpectrum;
				then assign toVHF.waterLevel := waterLevel;
				then send toVHF;
				then done;
			}
			then afterSending__6;


			state afterSending__6;

			transition from_afterSending__6__1 first afterSending__6
			then readingIMUData;


			state computingDerivedMeasurements;

			transition from_computingDerivedMeasurements__0 first computingDerivedMeasurements
			then sendingMeasurements;


			state readingIMUData;

			transition from_readingIMUData__0 first readingIMUData
			do action  {
				first start;
				then action msg accept IMUData : __type_Controller_IMUData;
				then assign IMU_xAcc := msg.IMUData.IMU_xAcc;
				then assign IMU_yAcc := msg.IMUData.IMU_yAcc;
				then assign IMU_zAcc := msg.IMUData.IMU_zAcc;
				then assign IMU_pitchRate := msg.IMUData.IMU_pitchRate;
				then assign IMU_rollRate := msg.IMUData.IMU_rollRate;
				then assign IMU_yawRate := msg.IMUData.IMU_yawRate;
				then done;
			}
			then afterReceiving__7;


			state afterReceiving__7;

			transition from_afterReceiving__7__1 first afterReceiving__7
			then readingGNSSData;


			state start__;

			transition from_start____0 first start__
			then readingIMUData;


		}
	}

