	part def Block__VHFTransmitter {
		attribute IMU_xAcc : Integer;
		attribute IMU_yAcc : Integer;
		attribute IMU_zAcc : Integer;
		attribute IMU_pitchRate : Integer;
		attribute IMU_rollRate : Integer;
		attribute IMU_yawRate : Integer;
		attribute GNSS_x : Integer;
		attribute GNSS_y : Integer;
		attribute GNSS_z : Integer;
		attribute airTemp : Integer;
		attribute waterTemp : Integer;
		attribute pressure : Integer;
		attribute windSpeed : Integer;
		attribute windDirection : Integer;
		attribute windGust : Integer;
		attribute humidity : Integer;
		attribute wavePropagationDirection : Integer;
		attribute waveEnergySpectrum : Integer;
		attribute waterLevel : Integer;

		// Signals
		in item fromController :  __type_VHFTransmitter_fromController;


		state mainState__ {
			entry; then start__;


			state waitingControllerData;

			transition from_waitingControllerData__0 first waitingControllerData
			do action  {
				first start;
				then action msg accept fromController : __type_VHFTransmitter_fromController;
				then assign IMU_xAcc := msg.fromController.IMU_xAcc;
				then assign IMU_yAcc := msg.fromController.IMU_yAcc;
				then assign IMU_zAcc := msg.fromController.IMU_zAcc;
				then assign IMU_pitchRate := msg.fromController.IMU_pitchRate;
				then assign IMU_rollRate := msg.fromController.IMU_rollRate;
				then assign IMU_yawRate := msg.fromController.IMU_yawRate;
				then assign GNSS_x := msg.fromController.GNSS_x;
				then assign GNSS_y := msg.fromController.GNSS_y;
				then assign GNSS_z := msg.fromController.GNSS_z;
				then assign airTemp := msg.fromController.airTemp;
				then assign waterTemp := msg.fromController.waterTemp;
				then assign pressure := msg.fromController.pressure;
				then assign windSpeed := msg.fromController.windSpeed;
				then assign windDirection := msg.fromController.windDirection;
				then assign windGust := msg.fromController.windGust;
				then assign humidity := msg.fromController.humidity;
				then assign wavePropagationDirection := msg.fromController.wavePropagationDirection;
				then assign waveEnergySpectrum := msg.fromController.waveEnergySpectrum;
				then assign waterLevel := msg.fromController.waterLevel;
				then done;
			}
			then afterReceiving__0;


			state afterReceiving__0;

			transition from_afterReceiving__0__1 first afterReceiving__0
			then waitingControllerData;


			state start__;

			transition from_start____0 first start__
			then waitingControllerData;


		}
	}

	// Usage of parts
	part Controller : Block__Controller {
	}

	part IMU : Block__IMU {
	}

	part GNSSReceiver : Block__GNSSReceiver {
	}

	part HumiditySensor : Block__HumiditySensor {
	}

	part Anemometer : Block__Anemometer {
	}

	part Barometer : Block__Barometer {
	}

	part WaterThermometer : Block__WaterThermometer {
	}

	part AirThermometer : Block__AirThermometer {
	}

	part VHFTransmitter : Block__VHFTransmitter {
	}

	// Connection between signals
	enum def CommunicationKind {
		synchronous;
		asynchronous;
	}

	connect Controller.toVHF to VHFTransmitter.fromController  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect IMU.IMUData to Controller.IMUData  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect GNSSReceiver.GNSSData to Controller.GNSSData  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect Anemometer.AnemometerData to Controller.AnemometerData  {
		communicationKind = CommunicationKind::synchronous;
		isPrivate = true;
		isLossy = false;

	}

	connect Barometer.BarometerData to Controller.BarometerData  {
		communicationKind = CommunicationKind::synchronous;
